/**
 * Type declarations for plotly.js-dist-min.
 *
 * This is the minified Plotly bundle — it exposes the same API as
 * the full `plotly.js` package but has no dedicated @types package.
 * We re-export the types from the main plotly.js type definitions.
 */
declare module "plotly.js-dist-min" {
  export * from "plotly.js";
}
